// Typed access to docs/data.json — the benchmark report generated by
// scripts/run-benchmarks.mjs. Consumed at build time by Astro pages.

import raw from "@data/data.json";

export interface BenchEntry {
  name: string;
  hz: number;
  rme: number;
  samples: number;
}

export interface BenchSuite {
  file: string;
  name: string;
  entries: BenchEntry[];
}

interface Report {
  generatedAt: string;
  nodeVersion: string;
  platform: string;
  benchmarks: {
    suites: BenchSuite[];
  };
}

const report = raw as unknown as Report;

export const generatedAt: string = report.generatedAt;
export const nodeVersion: string = report.nodeVersion;
export const platform: string = report.platform;
export const suites: BenchSuite[] = report.benchmarks.suites;

/** Find a suite whose name contains the given fragment (case-insensitive). */
export function findSuite(fragment: string): BenchSuite | undefined {
  const needle = fragment.toLowerCase();
  return suites.find((s) => s.name.toLowerCase().includes(needle));
}

/** All suites whose source file is under the given crate directory. */
export function suitesForCrate(crate: string): BenchSuite[] {
  return suites.filter((s) => s.file.startsWith(`crates/${crate}/`));
}

/** Pretty-format hz as 1.23K / 4.56M / 789. */
export function formatHz(hz: number): string {
  if (hz >= 1_000_000) return `${(hz / 1_000_000).toFixed(2)}M`;
  if (hz >= 1_000) return `${(hz / 1_000).toFixed(2)}K`;
  if (hz >= 100) return hz.toFixed(0);
  if (hz >= 10) return hz.toFixed(1);
  return hz.toFixed(2);
}

/** Speedup multiplier of `entry` vs the slowest entry in `entries`. */
export function speedupRatio(entry: BenchEntry, entries: BenchEntry[]): number {
  const slowest = entries.reduce((min, e) => (e.hz < min.hz ? e : min), entries[0]);
  return entry.hz / slowest.hz;
}

/** True when this entry is an @amigo-labs implementation. */
export function isAmigo(entry: BenchEntry): boolean {
  return entry.name.startsWith("@amigo-labs/");
}

export type Tier = "napi" | "wasm" | null;

/** The "tier" of an amigo bench entry — which binding produced the number.
 *  `null` for competitors and for legacy unsuffixed amigo entries. */
export function entryTier(entry: BenchEntry): Tier {
  if (!isAmigo(entry)) return null;
  if (entry.name.includes("(napi)")) return "napi";
  if (entry.name.includes("(wasm)")) return "wasm";
  return null;
}
